import type { ComponentProps, ComponentRef, ForwardedRef, ReactElement, ReactNode } from 'react';
import {
  Select as SelectPrimitive,
  type CollectionItem,
  type SelectRootComponent as ArkSelectRootComponent,
  type SelectRootProps as ArkSelectRootProps,
  type SelectRootProviderComponent as ArkSelectRootProviderComponent,
  type SelectRootProviderProps as ArkSelectRootProviderProps,
  useSelect,
  useSelectContext,
  useSelectItemContext,
} from '@ark-ui/react/select';
import { clsx } from 'clsx';
import { Children, cloneElement, forwardRef } from 'react';
import { CheckIcon, ChevronUpDownIcon, CloseIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import styles from './Select.module.css';

type SelectNativeFormControl = 'select' | 'input';
type SelectRootOwnProps = OverlayPortalProps & {
  nativeFormControl?: SelectNativeFormControl;
};
type SelectRootProps<T extends CollectionItem> = ArkSelectRootProps<T> & SelectRootOwnProps;
type SelectRootProviderProps<T extends CollectionItem> = ArkSelectRootProviderProps<T> &
  SelectRootOwnProps;
type SelectRootComponent = ArkSelectRootComponent<SelectRootOwnProps>;
type SelectRootProviderComponent = ArkSelectRootProviderComponent<SelectRootOwnProps>;
type SelectFieldProps = Omit<
  ComponentProps<typeof SelectPrimitive.Control>,
  'asChild' | 'children'
> & {
  clearLabel?: string;
  indicator?: ReactNode;
  placeholder?: ComponentProps<typeof SelectPrimitive.ValueText>['placeholder'];
};

const SelectRoot = forwardRef(function SelectRoot<T extends CollectionItem>(
  {
    asChild,
    children,
    className,
    nativeFormControl = 'select',
    portalled,
    portalRef,
    ...props
  }: SelectRootProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <SelectPrimitive.Root
        ref={ref}
        data-slot="select-root"
        className={clsx(styles.root, normalizeClassName(className))}
        asChild={asChild}
        {...props}
      >
        {withNativeFormControl(children, asChild, nativeFormControl)}
      </SelectPrimitive.Root>
    </OverlayPortalProvider>
  );
}) as SelectRootComponent;

const SelectRootProvider = forwardRef(function SelectRootProvider<T extends CollectionItem>(
  {
    asChild,
    children,
    className,
    nativeFormControl = 'select',
    portalled,
    portalRef,
    ...props
  }: SelectRootProviderProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <SelectPrimitive.RootProvider
        ref={ref}
        data-slot="select-root-provider"
        className={clsx(styles.root, normalizeClassName(className))}
        asChild={asChild}
        {...props}
      >
        {withNativeFormControl(children, asChild, nativeFormControl)}
      </SelectPrimitive.RootProvider>
    </OverlayPortalProvider>
  );
}) as SelectRootProviderComponent;

const SelectLabel = forwardRef<
  ComponentRef<typeof SelectPrimitive.Label>,
  ComponentProps<typeof SelectPrimitive.Label>
>(function SelectLabel({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Label
      ref={ref}
      data-slot="select-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectControl = forwardRef<
  ComponentRef<typeof SelectPrimitive.Control>,
  ComponentProps<typeof SelectPrimitive.Control>
>(function SelectControl({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Control
      ref={ref}
      data-slot="select-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectTrigger = forwardRef<
  ComponentRef<typeof SelectPrimitive.Trigger>,
  ComponentProps<typeof SelectPrimitive.Trigger>
>(function SelectTrigger({ asChild, className, ...props }, ref) {
  return (
    <SelectPrimitive.Trigger
      ref={ref}
      data-slot="select-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectValueText = forwardRef<
  ComponentRef<typeof SelectPrimitive.ValueText>,
  ComponentProps<typeof SelectPrimitive.ValueText>
>(function SelectValueText({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ValueText
      ref={ref}
      data-slot="select-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectClearTrigger = forwardRef<
  ComponentRef<typeof SelectPrimitive.ClearTrigger>,
  ComponentProps<typeof SelectPrimitive.ClearTrigger>
>(function SelectClearTrigger({ className, children, ...props }, ref) {
  return (
    <SelectPrimitive.ClearTrigger
      ref={ref}
      data-slot="select-clear-trigger"
      className={clsx(styles.clearTrigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CloseIcon />}
    </SelectPrimitive.ClearTrigger>
  );
});

const SelectIndicator = forwardRef<
  ComponentRef<typeof SelectPrimitive.Indicator>,
  ComponentProps<typeof SelectPrimitive.Indicator>
>(function SelectIndicator({ className, children, ...props }, ref) {
  return (
    <SelectPrimitive.Indicator
      ref={ref}
      data-slot="select-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronUpDownIcon />}
    </SelectPrimitive.Indicator>
  );
});

function SelectIndicators({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div
      data-slot="select-indicators"
      className={clsx(styles.indicators, normalizeClassName(className))}
      {...props}
    />
  );
}

const SelectField = forwardRef<ComponentRef<typeof SelectPrimitive.Control>, SelectFieldProps>(
  function SelectField({ clearLabel, indicator, placeholder, ...props }, ref) {
    return (
      <SelectControl ref={ref} {...props}>
        <SelectTrigger>
          <SelectValueText placeholder={placeholder} />
        </SelectTrigger>
        <SelectIndicators>
          {clearLabel && <SelectClearTrigger aria-label={clearLabel} />}
          <SelectIndicator>{indicator}</SelectIndicator>
        </SelectIndicators>
      </SelectControl>
    );
  },
);

const SelectPositioner = forwardRef<
  ComponentRef<typeof SelectPrimitive.Positioner>,
  ComponentProps<typeof SelectPrimitive.Positioner>
>(function SelectPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <SelectPrimitive.Positioner
        ref={ref}
        data-slot="select-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const SelectContent = forwardRef<
  ComponentRef<typeof SelectPrimitive.Content>,
  ComponentProps<typeof SelectPrimitive.Content>
>(function SelectContent({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Content
      ref={ref}
      data-slot="select-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectList = forwardRef<
  ComponentRef<typeof SelectPrimitive.List>,
  ComponentProps<typeof SelectPrimitive.List>
>(function SelectList({ className, ...props }, ref) {
  return (
    <SelectPrimitive.List
      ref={ref}
      data-slot="select-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemGroup = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemGroup>,
  ComponentProps<typeof SelectPrimitive.ItemGroup>
>(function SelectItemGroup({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ItemGroup
      ref={ref}
      data-slot="select-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemGroupLabel = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemGroupLabel>,
  ComponentProps<typeof SelectPrimitive.ItemGroupLabel>
>(function SelectItemGroupLabel({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ItemGroupLabel
      ref={ref}
      data-slot="select-item-group-label"
      className={clsx(styles.itemGroupLabel, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItem = forwardRef<
  ComponentRef<typeof SelectPrimitive.Item>,
  ComponentProps<typeof SelectPrimitive.Item>
>(function SelectItem({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Item
      ref={ref}
      data-slot="select-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemText = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemText>,
  ComponentProps<typeof SelectPrimitive.ItemText>
>(function SelectItemText({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ItemText
      ref={ref}
      data-slot="select-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemIndicator = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemIndicator>,
  ComponentProps<typeof SelectPrimitive.ItemIndicator>
>(function SelectItemIndicator({ className, children, ...props }, ref) {
  return (
    <SelectPrimitive.ItemIndicator
      ref={ref}
      data-slot="select-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CheckIcon />}
    </SelectPrimitive.ItemIndicator>
  );
});

function withNativeFormControl(
  children: ReactNode,
  asChild: boolean | undefined,
  nativeFormControl: SelectNativeFormControl,
) {
  const formControl = <SelectFormControl nativeFormControl={nativeFormControl} />;

  if (!asChild) {
    return (
      <>
        {children}
        {formControl}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, formControl);
}

function SelectFormControl({ nativeFormControl }: { nativeFormControl: SelectNativeFormControl }) {
  const select = useSelectContext();

  if (nativeFormControl === 'select') {
    return <SelectPrimitive.HiddenSelect data-slot="select-hidden-select" />;
  }

  const hiddenSelectProps = select.getHiddenSelectProps();

  return (
    <>
      {select.value.map((value) => (
        <input
          key={value}
          type="hidden"
          data-slot="select-hidden-input"
          name={hiddenSelectProps.name}
          form={hiddenSelectProps.form}
          autoComplete={hiddenSelectProps.autoComplete}
          disabled={hiddenSelectProps.disabled}
          value={value}
        />
      ))}
    </>
  );
}

function SelectItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-content"
      className={clsx(styles.itemTextContent, normalizeClassName(className))}
      {...props}
    />
  );
}

function SelectItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-icon"
      className={clsx(styles.itemTextIcon, normalizeClassName(className))}
      {...props}
    />
  );
}

function SelectItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-label"
      className={clsx(styles.itemTextLabel, normalizeClassName(className))}
      {...props}
    />
  );
}

const Select = Object.assign(SelectRoot, {
  Root: SelectRoot,
  RootProvider: SelectRootProvider,
  Context: SelectPrimitive.Context,
  ItemContext: SelectPrimitive.ItemContext,
  useSelect,
  useSelectContext,
  useSelectItemContext,
  Label: SelectLabel,
  Control: SelectControl,
  Field: SelectField,
  Trigger: SelectTrigger,
  ValueText: SelectValueText,
  ClearTrigger: SelectClearTrigger,
  Indicator: SelectIndicator,
  Indicators: SelectIndicators,
  Positioner: SelectPositioner,
  Content: SelectContent,
  List: SelectList,
  ItemGroup: SelectItemGroup,
  ItemGroupLabel: SelectItemGroupLabel,
  Item: SelectItem,
  ItemText: SelectItemText,
  ItemIndicator: SelectItemIndicator,
  ItemTextContent: SelectItemTextContent,
  ItemTextIcon: SelectItemTextIcon,
  ItemTextLabel: SelectItemTextLabel,
});

export { Select };

@layer ui.components {
  @keyframes select-content-open {
    from {
      opacity: var(--select-content-closed-opacity, var(--popup-motion-starting-opacity, 0));
      translate: var(--popup-motion-starting-translate-x, 0)
        var(--popup-motion-starting-translate-y, 0);
      transform: scale(
        var(--select-content-closed-scale, var(--popup-motion-starting-scale, var(--scale-popup)))
      );
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes select-content-closed {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(--select-content-closed-opacity, var(--popup-motion-ending-opacity, 0));
      translate: var(--popup-motion-ending-translate-x, 0) var(--popup-motion-ending-translate-y, 0);
      transform: scale(
        var(--select-content-closed-scale, var(--popup-motion-ending-scale, var(--scale-popup)))
      );
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--select-width, 14rem);
    max-width: var(--select-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    gap: var(--select-root-gap, 0.375rem);
    color: var(--select-color, var(--color-foreground));
  }

  .label {
    display: inline-flex;
    align-items: center;
    color: var(--select-label-color, var(--select-color, var(--color-foreground)));
    font-size: var(--select-label-font-size, var(--text-sm));
    font-weight: var(--select-label-font-weight, var(--weight-medium));
    line-height: var(--select-label-line-height, var(--line-height-text-sm));
    user-select: none;

    &[data-disabled] {
      opacity: var(--select-disabled-opacity, var(--opacity-disabled));
    }
  }

  .control {
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    align-items: center;
    color: var(--select-color, var(--color-foreground));

    &[data-disabled] {
      opacity: var(--select-disabled-opacity, var(--opacity-disabled));
    }
  }

  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    width: 100%;
    min-width: 0;
    height: var(--select-control-height, var(--size-lg));
    align-items: center;
    justify-content: flex-start;
    margin: 0;
    border: var(--select-border-width, var(--border-width-sm)) solid
      var(--select-border-color, var(--color-border));
    border-radius: var(--select-radius, var(--radius-md));
    padding-inline: var(--select-trigger-padding-x-start, 0.875rem)
      calc(
        var(--select-action-offset-right, 0.5rem) + var(--select-action-size, 1.5rem) +
          var(--select-trigger-padding-x-start, 0.875rem)
      );
    background-color: var(--select-bg, var(--color-background));
    color: inherit;
    font: inherit;
    text-align: start;
    outline: var(--select-focus-ring-width, var(--border-width-sm)) solid transparent;
    outline-offset: calc(var(--select-focus-ring-width, var(--border-width-sm)) * -1);
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--select-transition, var(--transition-default)),
      border-color var(--select-transition, var(--transition-default)),
      outline-color var(--select-transition, var(--transition-default));

    &[data-placeholder-shown] {
      color: var(--select-placeholder-color, var(--color-muted-foreground));
    }

    &[data-state='open'] {
      background-color: var(--select-bg-active, var(--color-muted));
      border-color: var(--select-focus-ring-color, var(--color-ring));
      outline-color: var(--select-focus-ring-color, var(--color-ring));
    }

    &[data-disabled],
    &[disabled] {
      cursor: default;
    }

    .control[data-focus] & {
      border-color: var(--select-focus-ring-color, var(--color-ring));
      outline-color: var(--select-focus-ring-color, var(--color-ring));
    }

    .control[data-invalid] & {
      border-color: var(--select-invalid-color, var(--color-destructive));
      outline-color: var(--select-invalid-color, var(--color-destructive));
    }

    .control:not([data-disabled]) & {
      @media (hover: hover) {
        &:hover {
          background-color: var(--select-bg-hover, var(--color-accent));
        }
      }
    }
  }

  .control:has(.clearTrigger:not([hidden])) .trigger {
    padding-inline-end: var(--select-trigger-padding-x-end, 4.25rem);
  }

  .valueText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .indicators {
    position: absolute;
    top: 50%;
    right: var(--select-action-offset-right, 0.5rem);
    display: inline-flex;
    align-items: center;
    gap: var(--select-action-gap, 0.125rem);
    line-height: 0;
    pointer-events: none;
    transform: translateY(-50%);
  }

  .indicator,
  .clearTrigger {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--select-action-size, 1.5rem);
    height: var(--select-action-size, 1.5rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--select-action-radius, var(--radius-sm));
    padding: 0;
    background: var(--select-action-bg, transparent);
    color: var(--select-icon-color, var(--color-muted-foreground));
    line-height: 0;
    transition:
      background-color var(--select-transition, var(--transition-default)),
      color var(--select-transition, var(--transition-default)),
      opacity var(--select-transition, var(--transition-default));

    & > svg {
      display: block;
      width: var(--select-icon-size, 1rem);
      height: var(--select-icon-size, 1rem);
    }

    &[data-disabled],
    &[disabled] {
      cursor: default;
    }

    &[hidden] {
      display: none;
    }
  }

  .indicator {
    pointer-events: none;
  }

  .clearTrigger {
    cursor: pointer;
    pointer-events: auto;

    &:not(:is([disabled], [data-disabled])) {
      @media (hover: hover) {
        &:hover {
          background-color: var(--select-action-bg-hover, var(--color-muted));
          color: var(--select-action-color-hover, var(--color-foreground));
        }
      }
    }
  }

  .positioner {
    z-index: var(--z-index);
    outline: 0;
  }

  .content {
    box-sizing: border-box;
    z-index: calc(var(--z-popup) + var(--layer-index, 0));
    display: flex;
    min-width: var(--reference-width);
    max-width: var(--available-width);
    max-height: min(var(--select-content-max-height, 24rem), var(--available-height));
    flex-direction: column;
    overflow: auto;
    border: var(--select-content-border-width, var(--border-width-sm)) solid
      var(--select-content-border-color, var(--color-border));
    border-radius: var(--select-radius, var(--radius-md));
    padding-block: var(--select-content-padding-y, var(--spacing-1));
    background-color: var(--select-content-bg, var(--color-popover));
    box-shadow: var(--select-content-shadow, var(--shadow-lg));
    color: var(--select-content-color, var(--color-popover-foreground));
    transform-origin: var(--transform-origin);
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--select-content-padding-y, var(--spacing-1));

    &[data-state='open'] {
      animation: select-content-open
        var(
          --select-transition,
          var(--popup-motion-duration, var(--duration-normal))
            var(--popup-motion-easing, var(--ease-in-out))
        );
    }

    &[data-state='closed'] {
      animation: select-content-closed
        var(
          --select-transition,
          var(--popup-motion-duration, var(--duration-normal))
            var(--popup-motion-easing, var(--ease-in-out))
        );
      pointer-events: none;
    }
  }

  .list {
    display: flex;
    min-height: 0;
    flex-direction: column;
    overflow-y: auto;
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--select-content-padding-y, var(--spacing-1));
  }

  .itemGroup {
    display: flex;
    flex-direction: column;

    & + & {
      margin-top: var(--select-item-group-gap, var(--spacing-2));
    }
  }

  .itemGroupLabel {
    padding-block: var(--select-item-group-label-padding-y, 0.375rem);
    padding-inline: var(--select-item-group-label-padding-x, 0.625rem);
    color: var(--select-item-group-label-color, var(--color-muted-foreground));
    font-size: var(--select-item-group-label-font-size, var(--text-xs));
    font-weight: var(--select-item-group-label-font-weight, var(--weight-semibold));
    line-height: var(--select-item-group-label-line-height, var(--line-height-text-xs));
  }

  .item {
    position: relative;
    box-sizing: border-box;
    display: flex;
    width: calc(100% - var(--select-item-inset-x, var(--spacing-2)));
    min-height: var(--select-item-min-height, 2rem);
    align-items: center;
    justify-content: space-between;
    gap: var(--select-item-gap, var(--spacing-2));
    margin-inline: calc(var(--select-item-inset-x, var(--spacing-2)) / 2);
    border: var(--select-item-border-width, 0) solid var(--select-item-border-color, transparent);
    border-radius: var(--select-item-radius, var(--radius-sm));
    padding-block: var(--select-item-padding-y, var(--spacing-2));
    padding-inline: var(--select-item-padding-x, 0.625rem);
    background-color: var(--select-item-bg, transparent);
    color: var(--select-item-color, var(--select-content-color, var(--color-foreground)));
    font: inherit;
    font-size: var(--select-item-font-size, var(--text-sm));
    line-height: var(--select-item-line-height, var(--line-height-text-sm));
    outline: 0;
    user-select: none;
    cursor: default;

    &[data-highlighted] {
      background-color: var(--select-highlight-bg, var(--color-accent));
      color: var(--select-highlight-color, var(--color-accent-foreground));
    }

    &[data-state='checked'] {
      color: var(--select-item-checked-color, var(--select-item-color, var(--color-foreground)));
    }

    &[data-disabled] {
      pointer-events: none;
      color: var(--select-item-disabled-color, var(--color-muted-foreground));
      opacity: var(--select-disabled-opacity, var(--opacity-disabled));
    }
  }

  .itemText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemIndicator {
    display: inline-flex;
    width: var(--select-item-indicator-size, 0.875rem);
    height: var(--select-item-indicator-size, 0.875rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    color: var(--select-item-indicator-color, currentColor);

    & > svg {
      width: var(--select-item-indicator-icon-size, 0.75rem);
      height: var(--select-item-indicator-icon-size, 0.75rem);
    }
  }

  .itemTextContent {
    display: inline-flex;
    max-width: 100%;
    min-width: 0;
    align-items: center;
    gap: var(--select-item-text-content-gap, var(--spacing-2));
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    width: var(--select-item-text-icon-size, 1rem);
    height: var(--select-item-text-icon-size, 1rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    color: var(--select-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}
